#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
int n,m,id[N],low[N],tot,len,cnt[N];
stack<int> st;vector<int> g[N];
vector<int> BCC[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u,int fa){
    id[u]=(++tot),low[u]=id[u];st.push(u);
    for(int v:g[u]){
        if(v==fa)continue;
        if(id[v])low[u]=min(low[u],id[v]);
        else{
            DFS(v,u),low[u]=min(low[u],low[v]);
            if(low[v]>=id[u]){
                vector<int> tmp;tmp.clear();
                tmp.pb(u),cnt[u]++;
                while(tmp.back()!=v)
                    tmp.pb(st.top()),cnt[st.top()]++,st.pop();
                BCC[++len]=tmp;
            }
        }
    }if(!fa&&cnt[u]==0)BCC[++len]={u};return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }for(int i=1;i<=n;i++)if(!id[i])DFS(i,0);
    cout<<len<<"\n";
    for(int i=1;i<=len;i++){
        cout<<BCC[i].size()<<" ";
        for(int x:BCC[i])cout<<x<<" ";cout<<"\n";
    }
    return 0;
}
